#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    double minmaxGasDist(vector<int>& stations, int K) {
        double lo = 0.0, hi = stations.back() - stations.front();
        for (int iter = 0; iter < 60; ++iter) {
            double mid = (lo + hi) / 2.0;
            long long needed = 0;
            for (size_t i = 1; i < stations.size(); ++i) {
                double gap = (double)stations[i] - stations[i-1];
                needed += (long long)ceil(gap / mid) - 1;
            }
            if (needed <= K) hi = mid; else lo = mid;
        }
        return hi;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    vector<int> stations(N);
    for (int i = 0; i < N; ++i) cin >> stations[i];
    int K;
    cin >> K;
    Solution sol;
    double ans = sol.minmaxGasDist(stations, K);
    // Print integer if close to integer
    if (fabs(ans - round(ans)) < 1e-9) {
        cout << (long long)llround(ans);
    } else {
        cout.setf(ios::fixed); cout << setprecision(10) << ans;
    }
    return 0;
}
